const Web3 = require('web3');
const fs = require('fs');

// Load the Ethereum network configuration
const config = JSON.parse(fs.readFileSync('config.json', 'utf8'));

// Initialize web3 with an HTTP provider (e.g., Infura or Alchemy)
const web3 = new Web3(new Web3.providers.HttpProvider(config.rpcUrl));

// Function to send ETH from one wallet to another
async function sendEth(fromAddress, toAddress, amountInEther) {
  const privateKey = config.privateKeys[fromAddress];
  const account = web3.eth.accounts.privateKeyToAccount(privateKey);

  // Convert the amount from Ether to Wei
  const amountInWei = web3.utils.toWei(amountInEther.toString(), 'ether');

  const transaction = {
    from: account.address,
    to: toAddress,
    value: amountInWei,
    gas: config.gasLimit,
    gasPrice: config.gasPrice,
  };

  // Sign the transaction
  const signedTransaction = await web3.eth.accounts.signTransaction(transaction, privateKey);

  // Send the signed transaction
  return web3.eth.sendSignedTransaction(signedTransaction.rawTransaction);
}

// Function to interact with a smart contract
async function interactWithContract(contractAddress, abi, functionName, fromAddress, ...params) {
  const privateKey = config.privateKeys[fromAddress];
  const account = web3.eth.accounts.privateKeyToAccount(privateKey);

  // Create the contract instance
  const contract = new web3.eth.Contract(abi, contractAddress, { from: account.address });

  // Estimate gas for the transaction
  const estimatedGas = await contract.methods[functionName](...params).estimateGas({ from: account.address });

  const transactionData = {
    to: contractAddress,
    data: contract.methods[functionName](...params).encodeABI(),
    gas: estimatedGas,
    gasPrice: config.gasPrice,
  };

  // Sign the transaction
  const signedTransaction = await web3.eth.accounts.signTransaction(transactionData, privateKey);

  // Send the signed transaction
  return web3.eth.sendSignedTransaction(signedTransaction.rawTransaction);
}

